import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.railway.com/reference/public-api";
const PLACEHOLDER_VALUE = "5afe10ca-1c0f-fee5-afe1-0ca1c0ffee5a";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Railway public API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:railway-project",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const railwayProjectFirewall = {",
    '  name: "railway-project",',
    '  description: "Railway public API (project-scoped token)",',
    "  placeholders: {",
    `    RAILWAY_PROJECT_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://backboard.railway.com",',
    "      auth: {",
    "        headers: {",
    '          "Project-Access-Token": "${{ secrets.RAILWAY_PROJECT_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Railway Project firewall config...");
  const ts = generateTypeScript();
  writeOutput("railway-project", ts, import.meta.dirname);
}
